proof fn phi_4_fold_left_sum_right_external_body_unsound(s: Seq<u64>, low: int)
    requires
        s.len() > 0,
    ensures
        s.subrange(0, s.len() - 1).fold_left(low, |b: int, a: u64| b + a.ghost_serialize().len())
            + s[s.len() - 1].ghost_serialize().len()
        ==
        s.fold_left(low, |b: int, a: u64| b + a.ghost_serialize().len()),
{
    let f = |a: u64| a.ghost_serialize();
    let fl = |a: u64| a.ghost_serialize().len() as int;
    assert((|b: int, a: u64| b + fl(a)) =~= (|b: int, a: u64| b + a.ghost_serialize().len()));
    lemma_seq_fold_left_sum_right::<u64>(s, low, fl);
}

